// ── 학습 콘텐츠 데이터 ───────────────────────────────────────────────────────
// 촉각 패턴은 dot-fossil의 실측 .dtms 자산을 그대로 사용.
// 600자 대문자 hex = 300 브라유 셀 (10행 × 30열, 셀당 8핀) = DotPad 320 한 화면.
// 서로 다른 패턴을 가진 부위 5종만 퀴즈 후보로 쓴다 — 별칭 패턴(shell=rib 등)은
// 촉각으로 구별이 불가능하므로 학습 문항에서 제외.

export interface PartDef {
  id: string;
  name: string;          // 부위 이름 (선택지·음성)
  nameEn: string;
  feel: string;          // 촉각 탐색 힌트 — 손끝으로 확인할 특징
  dinosaurId: string;
  dinosaurName: string;  // 주인 공룡 (Lv2 정답)
  dinosaurFact: string;  // 정답 후 들려주는 한 줄 지식
  hex: string;           // DotPad 320 촉각 패턴
}

